// ============================================================
//  NODE: Hash Data & Siapkan Payload Meta CAPI
// ============================================================

const crypto = require('crypto');

function sha256(value) {
  if (!value || value.toString().trim() === '') return null;
  return crypto
    .createHash('sha256')
    .update(value.toString().trim().toLowerCase())
    .digest('hex');
}

const row = $input.item.json;
const phone = (row.No_HP || '').toString().replace(/\D/g, '');
const nama = (row.Nama || '').toString().trim();
const eventId = (row.Event_ID || '').toString();
const paket = (row.Paket || '').toString();
const sourceUrl = (row.Source_URL || 'https://madubersanad.web.id').toString();
const orderValue = parseFloat((row.Order_Value || '0').toString().replace(/[^0-9.]/g, '')) || 0;

const bayarTime = row.Waktu_Bayar
  ? new Date(row.Waktu_Bayar).getTime() / 1000
  : Math.floor(Date.now() / 1000);

const userData = {
  country: ['62'],
};

if (phone) {
  const formattedPhone = phone.startsWith('0') ? '62' + phone.substring(1) : (phone.startsWith('62') ? phone : '62' + phone);
  userData.ph = [sha256(formattedPhone)];
}

if (nama) {
  const namaParts = nama.split(' ');
  userData.fn = [sha256(namaParts[0])];
  if (namaParts.length > 1) userData.ln = [sha256(namaParts.slice(1).join(' '))];
}

return {
  json: {
    data: [{
      event_name: 'Purchase',
      event_time: Math.floor(bayarTime),
      event_id: eventId + '_purchase',
      event_source_url: sourceUrl,
      action_source: 'website',
      user_data: userData,
      custom_data: {
        currency: 'IDR',
        value: orderValue,
        content_name: paket,
        content_type: 'product',
        order_id: eventId
      }
    }],
    _meta: {
      event_id: eventId
    }
  }
};
